sys_script_client.script:
function onSubmit() {

    var student = g_form.getValue('u_student');
    var team = g_form.getValue('u_team');

    var ga = new GlideAjax('CheckDuplicateTeamRequest');

    ga.addParam('sysparm_name', 'checkRequest');
    ga.addParam('sysparm_student', student);
    ga.addParam('sysparm_team', team);

    var response = ga.getXMLWait();
    var answer = response.documentElement.getAttribute('answer');

    if (answer == 'true') {

        alert("You already requested this team.");
        return false;
    }

    return true;
}
